(232, 1, '風', 9, 'N4', 232, 'Gió', 'Wind', 'フウ、フ', 'かぜ', 'Phong', 'Gió thổi côn trùng (虫) bay qua bụi cây.'),
(233, 1, '雲', 12, 'N4', 233, 'Mây', 'Cloud', 'ウン', 'くも', 'Vân', 'Mưa (雨) + nói (云) = mây trên trời.'),
(234, 1, '空', 8, 'N4', 234, 'Bầu trời', 'Sky, empty', 'クウ', 'そら、あ(く)', 'Không', 'Hang (穴) + công việc (工) = trống không.'),
(235, 1, '海', 9, 'N4', 235, 'Biển', 'Sea', 'カイ', 'うみ', 'Hải', 'Nước (氵) + mỗi (毎) = mọi nơi đều có biển.'),
(236, 1, '島', 10, 'N4', 236, 'Đảo', 'Island', 'トウ', 'しま', 'Đảo', 'Chim (鳥) đậu trên núi (山) trên biển.'),
(237, 1, '駅', 14, 'N4', 237, 'Ga (tàu)', 'Station', 'エキ', NULL, 'Trạm', 'Ngựa (馬) + thước (尺) = nơi dừng chân.'),
(238, 1, '通', 10, 'N4', 238, 'Đi qua', 'Pass through', 'ツウ', 'とお(る)、かよ(う)', 'Thông', 'Đi (辶) + dấu thông qua = đi qua.'),
(239, 1, '走', 7, 'N4', 239, 'Chạy', 'Run', 'ソウ', 'はし(る)', 'Tẩu', 'Đất (土) + chân (儿) = chạy.'),
(240, 1, '帰', 10, 'N4', 240, 'Về', 'Return', 'キ', 'かえ(る)', 'Quy', 'Hình người vác đồ về nhà.'),
(241, 1, '使', 8, 'N4', 241, 'Sử dụng', 'Use', 'シ', 'つか(う)', 'Sử', 'Người (人) + lịch sử (史) = sai khiến.'),
(242, 1, '働', 13, 'N4', 242, 'Làm việc', 'Work', 'ドウ', 'はたら(く)', 'Động', 'Người (人) + di chuyển (動) = lao động.'),
(243, 1, '勉', 10, 'N4', 243, 'Cố gắng', 'Effort', 'ベン', NULL, 'Miễn', 'Cùng (兔 dạng giản) + sức (力) = nỗ lực.'),
(244, 1, '強', 11, 'N4', 244, 'Mạnh', 'Strong', 'キョウ、ゴウ', 'つよ(い)', 'Cường', 'Cung (弓) + côn trùng = mạnh mẽ.'),
(245, 1, '弱', 10, 'N4', 245, 'Yếu', 'Weak', 'ジャク', 'よわ(い)', 'Nhược', 'Hai cánh cung yếu rủ xuống.'),
(246, 1, '正', 5, 'N4', 246, 'Đúng', 'Correct', 'セイ、ショウ', 'ただ(しい)', 'Chính', 'Một (一) + dừng (止) = đúng chỗ.'),
(247, 1, '悪', 11, 'N4', 247, 'Xấu', 'Bad, evil', 'アク、オ', 'わる(い)', 'Ác', 'Á (亜) + tâm (心) = xấu trong lòng.'),
(248, 1, '便', 9, 'N4', 248, 'Tiện lợi', 'Convenient', 'ベン、ビン', NULL, 'Tiện', 'Người (人) + thay đổi (更) = tiện ích.'),
(249, 1, '利', 7, 'N4', 249, 'Lợi ích', 'Profit', 'リ', 'き(く)', 'Lợi', 'Lúa (禾) + dao (刂) = thu hoạch lợi nhuận.'),
(250, 1, '思', 9, 'N4', 250, 'Nghĩ', 'Think', 'シ', 'おも(う)', 'Tư', 'Đầu (田) + tâm (心) = suy nghĩ.');

