(319, 3, '生', 5, 'HSK1', 20, 'Sống, sinh', 'Live, born', 'shēng', NULL, 'Sinh', 'Mầm cây mọc lên.'),
-- HSK 1 Common
(320, 3, '不', 4, 'HSK1', 21, 'Không', 'Not', 'bù', NULL, 'Bất', 'Phủ định.'),
(321, 3, '是', 9, 'HSK1', 22, 'Là', 'Be', 'shì', NULL, 'Thị', 'Mặt trời (日) đúng (正) = là đúng.'),
(322, 3, '有', 6, 'HSK1', 23, 'Có', 'Have', 'yǒu', NULL, 'Hữu', 'Tay cầm thịt = có.'),
(323, 3, '没', 7, 'HSK1', 24, 'Không có', 'Not have', 'méi', NULL, 'Mộc', 'Nước (氵) + vào trong = chìm xuống không có.'),
(324, 3, '好', 6, 'HSK1', 25, 'Tốt', 'Good', 'hǎo', NULL, 'Hảo', 'Phụ nữ (女) + con (子) = mẹ con là tốt.'),
(325, 3, '大', 3, 'HSK1', 26, 'Lớn', 'Big', 'dà', NULL, 'Đại', 'Người dang tay = lớn.'),
(326, 3, '小', 3, 'HSK1', 27, 'Nhỏ', 'Small', 'xiǎo', NULL, 'Tiểu', 'Ba chấm nhỏ.'),
(327, 3, '多', 6, 'HSK1', 28, 'Nhiều', 'Many', 'duō', NULL, 'Đa', 'Hai buổi tối (夕) chồng lên = nhiều.'),
(328, 3, '少', 4, 'HSK1', 29, 'Ít', 'Few', 'shǎo', NULL, 'Thiểu', 'Nhỏ (小) + một chấm = ít hơn.'),
(329, 3, '上', 3, 'HSK1', 30, 'Trên', 'Up', 'shàng', NULL, 'Thượng', 'Trên đường ngang.'),
(330, 3, '下', 3, 'HSK1', 31, 'Dưới', 'Down', 'xià', NULL, 'Hạ', 'Dưới đường ngang.'),
(331, 3, '中', 4, 'HSK1', 32, 'Giữa', 'Middle', 'zhōng', NULL, 'Trung', 'Mũi tên xuyên ô vuông.'),
(332, 3, '国', 8, 'HSK1', 33, 'Nước', 'Country', 'guó', NULL, 'Quốc', 'Vua (王) trong khu vực (口).'),
(333, 3, '中国', 4, 'HSK1', 34, 'Trung Quốc', 'China', 'zhōng guó', NULL, 'Trung Quốc', 'Đất nước trung tâm.'),
(334, 3, '日', 4, 'HSK1', 35, 'Ngày', 'Day, sun', 'rì', NULL, 'Nhật', 'Mặt trời.'),
(335, 3, '月', 4, 'HSK1', 36, 'Tháng', 'Moon, month', 'yuè', NULL, 'Nguyệt', 'Mặt trăng.'),
(336, 3, '年', 6, 'HSK1', 37, 'Năm', 'Year', 'nián', NULL, 'Niên', 'Người gánh lúa = một năm.'),
(337, 3, '今', 4, 'HSK1', 38, 'Nay', 'Now', 'jīn', NULL, 'Kim', 'Hiện tại.'),
(338, 3, '天', 4, 'HSK1', 39, 'Trời, ngày', 'Sky, day', 'tiān', NULL, 'Thiên', 'Đầu lớn (大) trên một (一) = bầu trời.'),
(339, 3, '明', 8, 'HSK1', 40, 'Sáng', 'Bright', 'míng', NULL, 'Minh', 'Mặt trời (日) + mặt trăng (月) = sáng.'),
(340, 3, '昨', 9, 'HSK1', 41, 'Hôm qua', 'Yesterday', 'zuó', NULL, 'Tạc', 'Mặt trời (日) + lúc trước (乍) = hôm qua.'),
(341, 3, '在', 6, 'HSK1', 42, 'Ở, đang', 'At, in', 'zài', NULL, 'Tại', 'Đất (土) + chỗ = đang ở.'),
(342, 3, '来', 7, 'HSK1', 43, 'Đến', 'Come', 'lái', NULL, 'Lai', 'Cây lúa chín = đến mùa thu hoạch.'),
(343, 3, '去', 5, 'HSK1', 44, 'Đi', 'Go', 'qù', NULL, 'Khứ', 'Đất (土) + tư (厶) = rời đi.'),
(344, 3, '看', 9, 'HSK1', 45, 'Nhìn, xem', 'Look', 'kàn', NULL, 'Khán', 'Tay (手) trên mắt (目) = nhìn xa.'),
(345, 3, '听', 7, 'HSK1', 46, 'Nghe', 'Listen', 'tīng', NULL, 'Thính', 'Miệng (口) + cân (斤) = nghe cẩn thận.'),
(346, 3, '说', 9, 'HSK1', 47, 'Nói', 'Speak', 'shuō', NULL, 'Thuyết', 'Ngôn (讠) + đổi (兑) = nói chuyện.'),
(347, 3, '吃', 6, 'HSK1', 48, 'Ăn', 'Eat', 'chī', NULL, 'Cật', 'Miệng (口) + ăn = nhai.'),
(348, 3, '喝', 12, 'HSK1', 49, 'Uống', 'Drink', 'hē', NULL, 'Hạt', 'Miệng (口) + cảm (曷) = uống.'),
(349, 3, '水', 4, 'HSK1', 50, 'Nước', 'Water', 'shuǐ', NULL, 'Thủy', 'Dòng nước chảy.'),
(350, 3, '茶', 9, 'HSK1', 51, 'Trà', 'Tea', 'chá', NULL, 'Trà', 'Cỏ (艹) + người (人) + cây (木) = lá trà.'),
(351, 3, '书', 4, 'HSK1', 52, 'Sách', 'Book', 'shū', NULL, 'Thư', 'Bút viết trên giấy.'),
(352, 3, '字', 6, 'HSK1', 53, 'Chữ', 'Character', 'zì', NULL, 'Tự', 'Mái nhà (宀) + con (子) = học chữ.'),
(353, 3, '家', 10, 'HSK1', 54, 'Nhà', 'Home', 'jiā', NULL, 'Gia', 'Mái nhà (宀) + heo (豕) = ngôi nhà.'),
(354, 3, '车', 4, 'HSK1', 55, 'Xe', 'Vehicle', 'chē', NULL, 'Xa', 'Bánh xe.'),
(355, 3, '时', 7, 'HSK1', 56, 'Thời gian', 'Time', 'shí', NULL, 'Thời', 'Mặt trời (日) + đền (寺) = thời gian.'),
(356, 3, '点', 9, 'HSK1', 57, 'Điểm, giờ', 'Dot, hour', 'diǎn', NULL, 'Điểm', 'Lửa (灬) + chiếm (占) = đốm sáng.'),
(357, 3, '钱', 10, 'HSK1', 58, 'Tiền', 'Money', 'qián', NULL, 'Tiền', 'Vàng (钅) + nhỏ (戋) = tiền nhỏ lẻ.'),
(358, 3, '买', 6, 'HSK1', 59, 'Mua', 'Buy', 'mǎi', NULL, 'Mãi', 'Đầu (亠) + lớn (大) = mua lớn.'),
(359, 3, '卖', 8, 'HSK1', 60, 'Bán', 'Sell', 'mài', NULL, 'Mại', 'Đầu (亠) + đất (土) + lớn = bán.');

-- ========================
-- GRAMMAR JAPANESE (extended) - JLPT N5/N4
-- ========================
INSERT INTO grammars (id, language_id, pattern, meaning_vi, meaning_en, structure, jlpt_level, example_sentence, example_translation, note) VALUES
-- N5 grammar (continuing from existing 1-3)
(100, 1, '〜が好きです', 'Thích ~', 'I like ~', 'Danh từ + が好きです', 'N5', 'わたしはねこがすきです。', 'Tôi thích mèo.', 'Trợ từ が dùng với すき/きらい/じょうず/へた.'),
(101, 1, '〜が嫌いです', 'Ghét ~', 'I dislike ~', 'Danh từ + が嫌いです', 'N5', 'わたしはトマトがきらいです。', 'Tôi ghét cà chua.', 'Cấu trúc tương tự すき.'),
(102, 1, '〜があります', 'Có ~ (vật)', 'There is ~ (thing)', 'Danh từ + があります', 'N5', 'つくえのうえにほんがあります。', 'Có sách trên bàn.', 'Dùng cho vật vô tri.'),
(103, 1, '〜がいます', 'Có ~ (người/động vật)', 'There is ~ (animate)', 'Danh từ + がいます', 'N5', 'こうえんにこどもがいます。', 'Có trẻ con ở công viên.', 'Dùng cho người và động vật.'),
(104, 1, '〜を + Verb', 'Tân ngữ + động từ', 'Object + verb', 'Danh từ + を + Vます', 'N5', 'ほんをよみます。', 'Đọc sách.', 'を là trợ từ tân ngữ trực tiếp.'),
(105, 1, '〜に行きます', 'Đi đến ~', 'Go to ~', 'Địa điểm + に + 行きます', 'N5', 'がっこうにいきます。', 'Đi đến trường.', 'に chỉ điểm đến của hành động.'),
(106, 1, '〜で + Vます', 'Tại/bằng ~ làm gì', 'At/by ~ do something', 'Nơi/phương tiện + で + Vます', 'N5', 'バスでがっこうにいきます。', 'Đi đến trường bằng xe buýt.', 'で chỉ phương tiện hoặc nơi diễn ra hành động.'),
(107, 1, '〜と + Vます', 'Cùng với ~', 'Together with ~', 'Người + と + Vます', 'N5', 'ともだちとはなします。', 'Nói chuyện với bạn.', 'と chỉ người cùng làm.'),
(108, 1, '〜から〜まで', 'Từ ~ đến ~', 'From ~ to ~', '〜から〜まで', 'N5', '9じから5じまではたらきます。', 'Làm việc từ 9 giờ đến 5 giờ.', 'Dùng cho cả thời gian và không gian.'),
(109, 1, 'Vませんか', 'Cùng làm ~ không?', 'Won''t you ~?', 'Vます stem + ませんか', 'N5', 'いっしょにえいがをみませんか。', 'Cùng xem phim không?', 'Lời mời lịch sự.'),
(110, 1, 'Vましょう', 'Hãy cùng ~', 'Let''s ~', 'Vます stem + ましょう', 'N5', 'べんきょうしましょう。', 'Hãy cùng học.', 'Lời rủ rê.'),
(111, 1, 'Vたいです', 'Muốn ~', 'Want to ~', 'Vます stem + たいです', 'N5', 'にほんへいきたいです。', 'Tôi muốn đi Nhật.', 'Diễn tả mong muốn của mình.'),
(112, 1, 'Vてください', 'Hãy ~', 'Please ~', 'Vて + ください', 'N5', 'まどをあけてください。', 'Hãy mở cửa sổ.', 'Yêu cầu lịch sự.'),
(113, 1, 'Vている', 'Đang ~', 'Be ~ing', 'Vて + いる', 'N5', 'いまべんきょうしています。', 'Bây giờ tôi đang học.', 'Hành động đang diễn ra hoặc trạng thái.'),
(114, 1, 'Adj-い', 'Tính từ đuôi い', 'I-adjective', 'い-Adj', 'N5', 'このりんごはあかいです。', 'Quả táo này đỏ.', 'Tính từ kết thúc bằng い.'),
(115, 1, 'Adj-な', 'Tính từ đuôi な', 'Na-adjective', 'な-Adj + な + N', 'N5', 'きれいなはなです。', 'Là bông hoa đẹp.', 'Cần な khi đứng trước danh từ.'),
(116, 1, 'い-Adj past', 'Quá khứ tính từ い', 'Past form of i-adj', 'い → かった + です', 'N5', 'きのうはあつかったです。', 'Hôm qua trời nóng.', 'Bỏ い → かった.'),
(117, 1, 'い-Adj negative', 'Phủ định tính từ い', 'Negative i-adj', 'い → くないです', 'N5', 'これはあまくないです。', 'Cái này không ngọt.', 'Bỏ い → くない.'),
(118, 1, 'V-ない form', 'Phủ định động từ', 'Negative form', 'V → ない', 'N5', 'にくをたべない。', 'Tôi không ăn thịt.', 'Thể phủ định thông thường.'),
(119, 1, '〜より〜のほうが', '~ hơn ~', '~ is more than ~', 'AよりBのほうが + Adj', 'N5', 'りんごよりみかんのほうがすきです。', 'Tôi thích quýt hơn táo.', 'So sánh hai vật/người.');

-- N4 grammar
INSERT INTO grammars (id, language_id, pattern, meaning_vi, meaning_en, structure, jlpt_level, example_sentence, example_translation, note) VALUES
(200, 1, '〜と思います', 'Tôi nghĩ rằng ~', 'I think that ~', 'Plain form + と思います', 'N4', 'あしたあめがふるとおもいます。', 'Tôi nghĩ ngày mai sẽ mưa.', 'Diễn tả ý kiến cá nhân.'),
(201, 1, '〜と言います', 'Nói rằng ~', '~ said that ~', 'Plain form + と言います', 'N4', 'たなかさんはいきますといいました。', 'Anh Tanaka nói sẽ đi.', 'Trích dẫn lời nói.'),
(202, 1, '〜ことができる', 'Có thể ~', 'Can ~', 'V dictionary + ことができる', 'N4', 'にほんごをはなすことができます。', 'Tôi có thể nói tiếng Nhật.', 'Thể hiện khả năng.'),
(203, 1, '〜たことがある', 'Đã từng ~', 'Have ~ before', 'Vた + ことがある', 'N4', 'にほんへいったことがあります。', 'Tôi đã từng đi Nhật.', 'Kinh nghiệm trong quá khứ.'),
(204, 1, '〜ながら', 'Vừa ~ vừa ~', 'While ~', 'Vます stem + ながら', 'N4', 'おんがくをききながらべんきょうします。', 'Vừa nghe nhạc vừa học.', 'Hai hành động cùng lúc.'),
(205, 1, '〜たり〜たり', 'Vừa ~ vừa ~ (liệt kê)', 'Doing ~ and ~', 'Vた + り Vた + りする', 'N4', 'にちようびはほんをよんだり、おんがくをきいたりします。', 'Chủ nhật tôi đọc sách và nghe nhạc.', 'Liệt kê các hành động.'),
(206, 1, '〜なければならない', 'Phải ~', 'Must ~', 'Vない → なければならない', 'N4', 'べんきょうしなければなりません。', 'Tôi phải học bài.', 'Nghĩa vụ, bắt buộc.'),
(207, 1, '〜てもいい', 'Được phép ~', 'May ~', 'Vて + もいい', 'N4', 'うちにかえってもいいですか。', 'Tôi về nhà được không?', 'Xin phép.'),
(208, 1, '〜てはいけない', 'Không được ~', 'Must not ~', 'Vて + はいけない', 'N4', 'ここでたばこをすってはいけません。', 'Không được hút thuốc ở đây.', 'Cấm đoán.'),
(209, 1, '〜ようになる', 'Trở nên ~', 'Become able to ~', 'V dict + ようになる', 'N4', 'にほんごがはなせるようになりました。', 'Tôi đã có thể nói tiếng Nhật.', 'Thay đổi về khả năng/thói quen.'),
(210, 1, '〜つもりです', 'Định ~', 'Plan to ~', 'V dict + つもりです', 'N4', 'らいねんにほんへいくつもりです。', 'Năm sau tôi định đi Nhật.', 'Dự định trong tương lai.'),
(211, 1, '〜ば〜', 'Nếu ~ thì ~', 'If ~', 'V conditional ば', 'N4', 'やすければかいます。', 'Nếu rẻ thì tôi mua.', 'Câu điều kiện.'),
(212, 1, '〜たら〜', 'Khi/Nếu ~ thì ~', 'When/If ~', 'Vた + ら', 'N4', 'いえにかえったら、でんわします。', 'Khi về nhà tôi sẽ gọi.', 'Điều kiện thời gian.'),
(213, 1, '〜と〜', 'Hễ ~ thì ~', 'When ~', 'V dict + と', 'N4', 'はるになると、はながさきます。', 'Hễ đến mùa xuân thì hoa nở.', 'Quy luật tự nhiên.');

-- ========================
-- GRAMMAR ENGLISH - CEFR A1/A2
-- ========================
INSERT INTO grammars (id, language_id, pattern, meaning_vi, meaning_en, structure, jlpt_level, example_sentence, example_translation, note) VALUES
(300, 2, 'Present Simple', 'Hiện tại đơn', 'Present simple tense', 'S + V(s/es)', 'A1', 'I work in London.', 'Tôi làm việc ở London.', 'Diễn tả thói quen, sự thật. Thêm s/es với ngôi 3 số ít.'),
(301, 2, 'Present Continuous', 'Hiện tại tiếp diễn', 'Present continuous', 'S + am/is/are + V-ing', 'A1', 'She is reading now.', 'Cô ấy đang đọc sách.', 'Hành động đang diễn ra tại thời điểm nói.'),
(302, 2, 'Past Simple', 'Quá khứ đơn', 'Past simple tense', 'S + V2/ed', 'A1', 'I visited Paris last year.', 'Tôi đã đến Paris năm ngoái.', 'Hành động đã hoàn thành trong quá khứ.'),
(303, 2, 'Future (will)', 'Tương lai (will)', 'Future with will', 'S + will + V', 'A1', 'I will call you tomorrow.', 'Tôi sẽ gọi cho bạn ngày mai.', 'Quyết định tức thời, dự đoán.'),
(304, 2, 'Future (be going to)', 'Tương lai (going to)', 'Be going to', 'S + am/is/are + going to + V', 'A1', 'We are going to eat.', 'Chúng tôi sẽ ăn.', 'Kế hoạch, dự định đã có sẵn.'),
(305, 2, 'A / An', 'Mạo từ a/an', 'Articles a/an', 'a + consonant; an + vowel', 'A1', 'a book, an apple', 'một quyển sách, một quả táo', 'A trước phụ âm, An trước nguyên âm.'),
(306, 2, 'The', 'Mạo từ the', 'Definite article', 'the + N (specific)', 'A1', 'The book on the table.', 'Quyển sách trên bàn.', 'Dùng khi xác định cụ thể.'),
(307, 2, 'Possessive ''s', 'Sở hữu cách', 'Possessive ''s', 'N + ''s + N', 'A1', 'John''s car.', 'Xe của John.', 'Sở hữu của người.'),
(308, 2, 'Possessive Adjectives', 'Tính từ sở hữu', 'My, your, his, her, its, our, their', 'PossAdj + N', 'A1', 'This is my book.', 'Đây là sách của tôi.', '7 tính từ sở hữu cơ bản.'),
(309, 2, 'There is / There are', 'Có ~', 'There is/are', 'There is + sing N; There are + plu N', 'A1', 'There is a cat. There are 3 cats.', 'Có một con mèo. Có 3 con mèo.', 'Diễn tả sự tồn tại.'),
(310, 2, 'Can (ability)', 'Có thể (khả năng)', 'Can for ability', 'S + can + V', 'A1', 'I can swim.', 'Tôi có thể bơi.', 'Khả năng làm việc gì.'),
(311, 2, 'Can (permission)', 'Có thể (xin phép)', 'Can for permission', 'Can + S + V?', 'A1', 'Can I go now?', 'Tôi có thể đi không?', 'Xin phép.'),
(312, 2, 'Must (obligation)', 'Phải (bắt buộc)', 'Must for obligation', 'S + must + V', 'A1', 'You must wear a helmet.', 'Bạn phải đội mũ bảo hiểm.', 'Sự bắt buộc.'),
(313, 2, 'Should (advice)', 'Nên (khuyên)', 'Should for advice', 'S + should + V', 'A1', 'You should rest more.', 'Bạn nên nghỉ ngơi nhiều hơn.', 'Lời khuyên.'),
(314, 2, 'Would like', 'Muốn (lịch sự)', 'Would like to', 'S + would like + N/to V', 'A1', 'I would like a coffee.', 'Tôi muốn một ly cà phê.', 'Cách nói lịch sự cho ''want''.'),
(315, 2, 'Prepositions of time', 'Giới từ thời gian', 'in/on/at for time', 'in (year/month), on (day), at (time)', 'A1', 'in 2025, on Monday, at 5pm', 'năm 2025, thứ Hai, 5h chiều', 'in - tháng/năm, on - ngày, at - giờ.'),
(316, 2, 'Prepositions of place', 'Giới từ chỉ nơi chốn', 'in/on/at for place', 'in (large area), on (surface), at (point)', 'A1', 'in the room, on the table, at the door', 'trong phòng, trên bàn, ở cửa', 'in - không gian kín, on - bề mặt, at - điểm.'),
(317, 2, 'Comparatives', 'So sánh hơn', 'Comparative adjectives', 'Adj-er than / more Adj than', 'A1', 'He is taller than me.', 'Anh ấy cao hơn tôi.', 'Tính từ ngắn + er, dài + more.'),
(318, 2, 'Superlatives', 'So sánh nhất', 'Superlative adjectives', 'the + Adj-est / the most Adj', 'A1', 'The tallest building.', 'Tòa nhà cao nhất.', 'Tính từ ngắn + est, dài + most.'),
(319, 2, 'Quantifiers (some/any)', 'Một vài / nào đó', 'Some / Any', 'some (positive), any (negative/question)', 'A2', 'I have some money. Do you have any money?', 'Tôi có ít tiền. Bạn có tiền không?', 'some khẳng định, any phủ định/câu hỏi.'),
(320, 2, 'Present Perfect', 'Hiện tại hoàn thành', 'Present perfect', 'S + have/has + V3', 'A2', 'I have visited Japan.', 'Tôi đã từng thăm Nhật Bản.', 'Kinh nghiệm hoặc hành động vừa hoàn thành.'),
(321, 2, 'Past Continuous', 'Quá khứ tiếp diễn', 'Past continuous', 'S + was/were + V-ing', 'A2', 'I was reading when she called.', 'Tôi đang đọc sách khi cô ấy gọi.', 'Hành động đang xảy ra trong quá khứ.'),
(322, 2, 'Used to', 'Đã từng', 'Used to + V', 'S + used to + V', 'A2', 'I used to live in Hanoi.', 'Tôi đã từng sống ở Hà Nội.', 'Thói quen trong quá khứ không còn nữa.'),
(323, 2, 'First Conditional', 'Câu điều kiện loại 1', 'If + present, will + V', 'If + S + V (pres), S + will + V', 'A2', 'If it rains, I will stay home.', 'Nếu trời mưa, tôi sẽ ở nhà.', 'Điều kiện có thể xảy ra.'),
(324, 2, 'Imperatives', 'Câu mệnh lệnh', 'Commands', 'V (base form)', 'A1', 'Sit down. Don''t talk!', 'Ngồi xuống. Đừng nói chuyện!', 'Lệnh, yêu cầu trực tiếp.'),
(325, 2, 'Wh-questions', 'Câu hỏi với từ Wh-', 'Wh- questions', 'Wh + aux + S + V?', 'A1', 'Where do you live?', 'Bạn sống ở đâu?', 'What/Where/When/Why/Who/How.');

-- ========================
-- GRAMMAR CHINESE - HSK 1/2/3
-- ========================
INSERT INTO grammars (id, language_id, pattern, meaning_vi, meaning_en, structure, jlpt_level, example_sentence, example_translation, note) VALUES
(400, 3, '是 (shì)', 'Là', 'To be', 'S + 是 + N', 'HSK1', '我是学生。', 'Tôi là học sinh.', 'Động từ ''là'' căn bản.'),
(401, 3, '不是 (bú shì)', 'Không phải là', 'Not be', 'S + 不是 + N', 'HSK1', '我不是老师。', 'Tôi không phải là giáo viên.', 'Phủ định của 是.'),
(402, 3, '吗 (ma)', '...phải không?', 'Yes/No question', 'S + V + 吗?', 'HSK1', '你是学生吗？', 'Bạn có phải là học sinh không?', 'Trợ từ tạo câu hỏi yes/no.'),
(403, 3, '呢 (ne)', '...thì sao?', 'And what about...?', 'N + 呢?', 'HSK1', '我很好，你呢？', 'Tôi khỏe, còn bạn?', 'Hỏi lại đối phương.'),
(404, 3, '的 (de)', 'Của', 'Possessive marker', 'A + 的 + N', 'HSK1', '我的书。', 'Sách của tôi.', 'Trợ từ sở hữu.'),
(405, 3, '在 (zài)', 'Đang/Ở', 'At, in (location)', 'S + 在 + Place', 'HSK1', '我在家。', 'Tôi ở nhà.', 'Chỉ vị trí hoặc đang làm.'),
(406, 3, '有 (yǒu)', 'Có', 'Have', 'S + 有 + N', 'HSK1', '我有一本书。', 'Tôi có một quyển sách.', 'Sở hữu hoặc tồn tại.'),
(407, 3, '没有 (méi yǒu)', 'Không có', 'Not have', 'S + 没有 + N', 'HSK1', '我没有钱。', 'Tôi không có tiền.', 'Phủ định của 有.'),
(408, 3, '很 (hěn)', 'Rất', 'Very', '很 + Adj', 'HSK1', '我很高兴。', 'Tôi rất vui.', 'Bắt buộc trước tính từ trong câu khẳng định.'),
(409, 3, '太...了', 'Quá ~', 'Too ~', '太 + Adj + 了', 'HSK1', '太好了！', 'Tốt quá!', 'Cảm thán quá mức.'),
(410, 3, '会 (huì)', 'Biết, có thể', 'Can (learned)', 'S + 会 + V', 'HSK1', '我会说汉语。', 'Tôi biết nói tiếng Trung.', 'Khả năng học được.'),
(411, 3, '能 (néng)', 'Có thể', 'Can (possible)', 'S + 能 + V', 'HSK1', '我能去。', 'Tôi có thể đi.', 'Khả năng vật lý hoặc cho phép.'),
(412, 3, '想 (xiǎng)', 'Muốn, nghĩ', 'Want, think', 'S + 想 + V', 'HSK1', '我想吃苹果。', 'Tôi muốn ăn táo.', 'Mong muốn hoặc suy nghĩ.'),
(413, 3, '要 (yào)', 'Muốn, sẽ', 'Want, will', 'S + 要 + V', 'HSK1', '我要去北京。', 'Tôi muốn đi Bắc Kinh.', 'Mong muốn hoặc kế hoạch.'),
(414, 3, '了 (le) - completion', 'Đã (hoàn thành)', 'Completed action', 'V + 了', 'HSK1', '我吃饭了。', 'Tôi đã ăn cơm rồi.', 'Trợ từ chỉ hoàn thành.'),
(415, 3, '了 (le) - change', 'Đã (thay đổi)', 'Change of state', 'S + Adj + 了', 'HSK1', '天气热了。', 'Trời nóng rồi.', 'Sự thay đổi trạng thái.'),
(416, 3, '吧 (ba)', '...nhé/...thôi', 'Suggestion/assumption', 'S + V + 吧', 'HSK1', '我们走吧。', 'Chúng ta đi thôi.', 'Đề nghị hoặc phỏng đoán.'),
(417, 3, '都 (dōu)', 'Đều, tất cả', 'All, both', 'S + 都 + V', 'HSK1', '我们都喜欢。', 'Chúng tôi đều thích.', 'Đứng trước động từ.'),
(418, 3, '和 (hé)', 'Và', 'And', 'A + 和 + B', 'HSK1', '我和你。', 'Tôi và bạn.', 'Liên từ ''và''.'),
(419, 3, '比 (bǐ)', 'So với', 'Comparison', 'A + 比 + B + Adj', 'HSK2', '我比你高。', 'Tôi cao hơn bạn.', 'Câu so sánh hơn.'),
(420, 3, '正在...呢', 'Đang ~', 'Be -ing', '正在 + V + 呢', 'HSK2', '我正在吃饭呢。', 'Tôi đang ăn cơm.', 'Hành động đang tiếp diễn.'),
(421, 3, '过 (guo)', 'Đã từng', 'Have ever ~', 'V + 过', 'HSK2', '我去过北京。', 'Tôi đã từng đến Bắc Kinh.', 'Kinh nghiệm.'),
(422, 3, '一边...一边', 'Vừa ~ vừa ~', 'While ~', '一边 + V1 + 一边 + V2', 'HSK2', '一边吃饭一边看电视。', 'Vừa ăn cơm vừa xem TV.', 'Hai hành động đồng thời.'),
(423, 3, '从...到...', 'Từ ~ đến ~', 'From ~ to ~', '从 + A + 到 + B', 'HSK2', '从家到学校。', 'Từ nhà đến trường.', 'Khoảng cách hoặc thời gian.'),
(424, 3, '虽然...但是', 'Mặc dù... nhưng', 'Although... but', '虽然 + S1, 但是 + S2', 'HSK3', '虽然累，但是开心。', 'Mặc dù mệt nhưng vui.', 'Mệnh đề nhượng bộ.'),
(425, 3, '因为...所以', 'Vì... nên', 'Because... so', '因为 + S1, 所以 + S2', 'HSK3', '因为下雨，所以不去。', 'Vì trời mưa nên không đi.', 'Mệnh đề nhân quả.');
